#### 3. Custom Health Indicators

```java
// src/main/java/com/example/health/RedisHealthIndicator.java
@Component
@RequiredArgsConstructor
public class RedisHealthIndicator implements HealthIndicator {

    private final RedisTemplate<String, String> redisTemplate;

    @Override
    public Health health() {
        try {
            // Simple ping
            String ping = redisTemplate.execute((RedisCallback<String>) connection -> 
                connection.ping());

            return "PONG".equals(ping) 
                ? Health.up().withDetail("ping", "PONG").build()
                : Health.down().withDetail("error", "Invalid Redis response").build();
        } catch (Exception e) {
            return Health.down(e)
                    .withDetail("error", "Redis connection failed")
                    .build();
        }
    }
}
```

```java
// ExternalApiHealthIndicator.java
@Component
@RequiredArgsConstructor
public class ExternalApiHealthIndicator implements HealthIndicator {

    private final WebClient webClient; // or RestClient in Spring 6

    @Override
    public Health health() {
        try {
            // Use a lightweight endpoint (health, ping, or status)
            Boolean isHealthy = webClient.get()
                    .uri("/health")
                    .retrieve()
                    .bodyToMono(Boolean.class)
                    .timeout(Duration.ofSeconds(3))
                    .block();

            return Boolean.TRUE.equals(isHealthy) 
                ? Health.up().build()
                : Health.down().withDetail("reason", "External API returned unhealthy").build();
        } catch (Exception e) {
            return Health.down(e)
                    .withDetail("error", "External API unreachable")
                    .build();
        }
    }
}
```

