```java
@Configuration
public class HealthConfig {

    @Bean
    public HealthContributorRegistry healthContributorRegistry(
            HealthIndicator dbHealthIndicator,
            RedisHealthIndicator redisHealthIndicator,
            ExternalApiHealthIndicator externalApiHealthIndicator) {

        return HealthContributorRegistry.of(
            Map.of(
                "db", dbHealthIndicator,
                "redis", redisHealthIndicator,
                "external-api", externalApiHealthIndicator
            )
        );
    }
}
```

