  containers:
  - name: my-service
    image: my-service:latest
    startupProbe:
      httpGet:
        path: /health/startup
        port: 3000
      failureThreshold: 30 # Allow 5 mins (30 * 10s) for migrations
      periodSeconds: 10
    livenessProbe:
